package ru.memearena.tournament.api; import ru.memearena.meme.domain.Meme; import ru.memearena.tournament.domain.*; import java.time.*; import java.util.*; public class TournamentDtos{ public record MemeDto(UUID id,String title,String imageUrl){} public record MatchDto(UUID id,int roundNumber,int matchNumber,String status,MemeDto left,MemeDto right,Long leftVotes,Long rightVotes,UUID selectedMemeId,UUID winnerMemeId,Instant startsAt,Instant endsAt){} public record TournamentDto(UUID id,LocalDate date,String status,int currentRound,Instant startsAt,List<MatchDto> matches,MemeDto winner){} public record HistoryItem(UUID id,LocalDate date,String status,MemeDto winner){} public static MemeDto meme(Meme m){return m==null?null:new MemeDto(m.getId(),m.getTitle(),m.getImageUrl());} }
